import hashlib
from typing import Optional, Dict, Any
import json
from tqdm import tqdm


class ModelDownloader:
    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.model_registry = {}
        
    def download_file(self, url: str, destination: Path, chunk_size: int = 8192):
        response = requests.get(url, stream=True)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        
        with open(destination, 'wb') as f, tqdm(
            desc=destination.name,
            total=total_size,
            unit='iB',
            unit_scale=True,
            unit_divisor=1024,
        ) as pbar:
            for chunk in response.iter_content(chunk_size=chunk_size):
                size = f.write(chunk)
                pbar.update(size)
    
    def get_cache_path(self, url: str) -> Path:
        url_hash = hashlib.md5(url.encode()).hexdigest()
        filename = url.split('/')[-1]
        return self.cache_dir / f"{url_hash}_{filename}"
    
    def download_model(self, url: str, force_download: bool = False) -> Path:
        cache_path = self.get_cache_path(url)
        
        if cache_path.exists() and not force_download:
            print(f"Using cached model: {cache_path}")
            return cache_path
        
        print(f"Downloading model from: {url}")
        self.download_file(url, cache_path)
        print(f"Model saved to: {cache_path}")
        
        return cache_path
    
    def load_checkpoint(self, url_or_path: str, map_location: str = 'cpu') -> Dict[str, Any]:
        if url_or_path.startswith('http://') or url_or_path.startswith('https://'):
            model_path = self.download_model(url_or_path)
        else:
            model_path = Path(url_or_path)
        
        checkpoint = torch.load(model_path, map_location=map_location)
        return checkpoint


class PretrainedModelLoader:
    def __init__(self, downloader: ModelDownloader):
        self.downloader = downloader
        
    def load_from_url(self, url: str, model_arch: Optional[nn.Module] = None, 
                      map_location: str = 'cpu') -> nn.Module:
        checkpoint = self.downloader.load_checkpoint(url, map_location)
        
        if model_arch is None:
            if 'model' in checkpoint:
                model = checkpoint['model']
            elif 'state_dict' in checkpoint:
                raise ValueError("state_dict found but no model architecture provided")
            else:
                model = checkpoint
        else:
            if 'state_dict' in checkpoint:
                model_arch.load_state_dict(checkpoint['state_dict'])
            elif 'model_state_dict' in checkpoint:
                model_arch.load_state_dict(checkpoint['model_state_dict'])
            else:
                model_arch.load_state_dict(checkpoint)
            model = model_arch
        
        return model
    
    def load_torchvision_model(self, model_name: str, pretrained: bool = True, 
                               num_classes: Optional[int] = None) -> nn.Module:
        model_fn = getattr(models, model_name)
        model = model_fn(pretrained=pretrained)
        
        if num_classes is not None:
            if hasattr(model, 'fc'):
                in_features = model.fc.in_features
                model.fc = nn.Linear(in_features, num_classes)
            elif hasattr(model, 'classifier'):
                if isinstance(model.classifier, nn.Sequential):
                    in_features = model.classifier[-1].in_features
                    model.classifier[-1] = nn.Linear(in_features, num_classes)
                else:
                    in_features = model.classifier.in_features
                    model.classifier = nn.Linear(in_features, num_classes)
        
        return model


class ModelFineTuner:
    def __init__(self, model: nn.Module, device: str = 'cuda' if torch.cuda.is_available() else 'cpu'):
        self.model = model.to(device)
        self.device = device
        self.history = {'train_loss': [], 'train_acc': [], 'val_loss': [], 'val_acc': []}
        
    def freeze_layers(self, freeze_until: Optional[str] = None, freeze_all: bool = False):
        if freeze_all:
            for param in self.model.parameters():
                param.requires_grad = False
        elif freeze_until:
            freeze = True
            for name, param in self.model.named_parameters():
                if freeze_until in name:
                    freeze = False
                if freeze:
                    param.requires_grad = False
        
    def unfreeze_layers(self, unfreeze_from: Optional[str] = None):
        if unfreeze_from is None:
            for param in self.model.parameters():
                param.requires_grad = True
        else:
            unfreeze = False
            for name, param in self.model.named_parameters():
                if unfreeze_from in name:
                    unfreeze = True
                if unfreeze:
                    param.requires_grad = True
    
    def train_epoch(self, dataloader: DataLoader, criterion: nn.Module, 
                   optimizer: optim.Optimizer) -> tuple:
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0
        
        for inputs, labels in tqdm(dataloader, desc="Training"):
            inputs, labels = inputs.to(self.device), labels.to(self.device)
            
            optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            
            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += labels.size(0)
            correct += predicted.eq(labels).sum().item()
        
        epoch_loss = running_loss / total
        epoch_acc = correct / total
        
        return epoch_loss, epoch_acc
    
    def validate(self, dataloader: DataLoader, criterion: nn.Module) -> tuple:
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in tqdm(dataloader, desc="Validation"):
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                
                outputs = self.model(inputs)
                loss = criterion(outputs, labels)
                
                running_loss += loss.item() * inputs.size(0)
                _, predicted = outputs.max(1)
                total += labels.size(0)
                correct += predicted.eq(labels).sum().item()
        
        epoch_loss = running_loss / total
        epoch_acc = correct / total
        
        return epoch_loss, epoch_acc
    
    def fine_tune(self, train_loader: DataLoader, val_loader: DataLoader,
                  num_epochs: int, learning_rate: float = 0.001,
                  optimizer_type: str = 'adam', scheduler_type: Optional[str] = None,
                  save_path: Optional[str] = None):
        
        criterion = nn.CrossEntropyLoss()
        
        if optimizer_type.lower() == 'adam':
            optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                  lr=learning_rate)
        elif optimizer_type.lower() == 'sgd':
            optimizer = optim.SGD(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                 lr=learning_rate, momentum=0.9)
        else:
            optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                  lr=learning_rate)
        
        scheduler = None
        if scheduler_type == 'step':
            scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=7, gamma=0.1)
        elif scheduler_type == 'cosine':
            scheduler = optim.lr_scheduler.CosineAnnealingLR(optimizer, T_max=num_epochs)
        
        best_val_acc = 0.0
        
        for epoch in range(num_epochs):
            print(f"\nEpoch {epoch+1}/{num_epochs}")
            print("-" * 50)
            
            train_loss, train_acc = self.train_epoch(train_loader, criterion, optimizer)
            val_loss, val_acc = self.validate(val_loader, criterion)
            
            self.history['train_loss'].append(train_loss)
            self.history['train_acc'].append(train_acc)
            self.history['val_loss'].append(val_loss)
            self.history['val_acc'].append(val_acc)
            
            print(f"Train Loss: {train_loss:.4f}, Train Acc: {train_acc:.4f}")
            print(f"Val Loss: {val_loss:.4f}, Val Acc: {val_acc:.4f}")
            
            if scheduler:
                scheduler.step()
            
            if val_acc > best_val_acc:
                best_val_acc = val_acc
                if save_path:
                    self.save_model(save_path, epoch, optimizer, val_acc)
                    print(f"Model saved with validation accuracy: {val_acc:.4f}")
        
        return self.history
    
    def save_model(self, path: str, epoch: int, optimizer: optim.Optimizer, 
                   val_acc: float):
        checkpoint = {
            'epoch': epoch,
            'model_state_dict': self.model.state_dict(),
            'optimizer_state_dict': optimizer.state_dict(),
            'val_acc': val_acc,
            'history': self.history
        }
        torch.save(checkpoint, path)


